// A regular function that returns a value:
function greet() {
  return 'Hello';
}
console.log(greet()); // 'Hello'

// The same function marked async:
async function greet() {
  return 'Hello';
}
console.log(greet()); // Promise { 'Hello' }
greet().then(msg => console.log(msg)); // 'Hello'

// Equivalent: returning a resolved Promise explicitly:
function greet() {
  return Promise.resolve('Hello');
}

async function alwaysFails() {
  throw new Error('Boom');
}

alwaysFails().catch(err => console.error(err.message)); // 'Boom'

// Equivalent Promise version:
function alwaysFails() {
  return Promise.reject(new Error('Boom'));
}

async function loadData() {
  // await pauses here until fetch() resolves:
  const response = await fetch('/api/data');

  // Execution resumes here with the resolved value:
  const data = await response.json();

  // data is the plain JS object — no .then() needed:
  console.log(data);
}

loadData(); // returns a Promise immediately; the above runs asynchronously

// Promise chain version:
function getUser(id) {
  return fetch(`/api/users/${id}`)
    .then(r => {
      if (!r.ok) throw new Error(`HTTP ${r.status}`);
      return r.json();
    })
    .then(user => user.name);
}

// async/await version — reads top-to-bottom like synchronous code:
async function getUser(id) {
  const r = await fetch(`/api/users/${id}`);
  if (!r.ok) throw new Error(`HTTP ${r.status}`);
  const user = await r.json();
  return user.name; // implicitly wraps in a Promise
}

async function fetchPost(id) {
  try {
    const response = await fetch(`/api/posts/${id}`);
    if (!response.ok) throw new Error(`HTTP ${response.status}`);

    const post = await response.json();
    return post;
  } catch (err) {
    // Catches both network errors and the thrown HTTP error above:
    console.error('Failed to load post:', err.message);
    return null;
  } finally {
    // Runs whether try succeeded or catch ran:
    console.log('Fetch attempt complete');
  }
}

// ❌ Sequential — total time = time(userFetch) + time(postsFetch)
async function loadDashboardSlow(userId) {
  const user  = await fetchUser(userId);   // waits for this to finish
  const posts = await fetchPosts(userId);  // only starts after user arrives
  return { user, posts };
}

// ✅ Parallel — total time = max(time(userFetch), time(postsFetch))
async function loadDashboardFast(userId) {
  const [user, posts] = await Promise.all([
    fetchUser(userId),
    fetchPosts(userId),
  ]);
  return { user, posts };
}

import { useState, useEffect } from 'react';

function UserProfile({ userId }) {
  const [user, setUser]       = useState(null);
  const [error, setError]     = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let cancelled = false;

    // ✅ Define the async work inside the effect:
    async function load() {
      try {
        const r = await fetch(`/api/users/${userId}`);
        if (!r.ok) throw new Error(`HTTP ${r.status}`);
        const data = await r.json();
        if (!cancelled) setUser(data);
      } catch (err) {
        if (!cancelled) setError(err.message);
      } finally {
        if (!cancelled) setLoading(false);
      }
    }

    load(); // call it immediately

    // Cleanup: ignore stale responses if userId changes before fetch completes
    return () => { cancelled = true; };
  }, [userId]);

  if (loading) return <p>Loading...</p>;
  if (error)   return <p>Error: {error}</p>;
  return <h1>{user.name}</h1>;
}

// ❌ Wrong — useEffect callback is async, returns a Promise:
useEffect(async () => {
  const data = await fetchData();
  setData(data);
  // The return value (a Promise) is treated as a cleanup function — React warning!
}, []);

// ✅ Correct — IIFE pattern (alternative to named inner function):
useEffect(() => {
  let cancelled = false;
  (async () => {
    const data = await fetchData();
    if (!cancelled) setData(data);
  })();
  return () => { cancelled = true; };
}, []);

useEffect(() => {
  const controller = new AbortController();

  async function load() {
    try {
      const r = await fetch(`/api/users/${userId}`, {
        signal: controller.signal,   // attach abort signal to the request
      });
      if (!r.ok) throw new Error(`HTTP ${r.status}`);
      const data = await r.json();
      setUser(data);
    } catch (err) {
      if (err.name === 'AbortError') return; // ignore — intentional cancellation
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }

  load();
  return () => controller.abort(); // cancels the request on cleanup
}, [userId]);

