// Sequential — process one at a time (useful when order or rate limiting matters):
async function loadUsersSequentially(ids) {
  const users = [];
  for (const id of ids) {
    const r    = await fetch(`/api/users/${id}`);
    const user = await r.json();
    users.push(user);
  }
  return users;
}

// Parallel — fire all at once and collect results:
async function loadUsersParallel(ids) {
  return Promise.all(
    ids.map(id => fetch(`/api/users/${id}`).then(r => r.json()))
  );
}

// ❌ Common mistake — forEach does not await:
async function broken(ids) {
  ids.forEach(async id => {
    const r = await fetch(`/api/users/${id}`);
    // This async callback runs, but forEach doesn't await its return value
    // — the function returns before all fetches complete
  });
  // All fetches are still pending here!
}
// ✅ Use for...of for sequential, Promise.all for parallel

// Function declaration:
async function fetchData() { return 'data'; }

// Arrow function (most common in React):
const fetchData = async () => 'data';

// Concise arrow — implicit return still wraps in a Promise:
const double = async (x) => x * 2;
double(3).then(console.log); // 6

