function ContactForm() {
  const [status, setStatus] = useState('idle'); // 'idle' | 'submitting' | 'success' | 'error'

  // Event handlers can be async:
  async function handleSubmit(e) {
    e.preventDefault();
    setStatus('submitting');

    try {
      const formData = new FormData(e.target);
      const r = await fetch('/api/contact', {
        method: 'POST',
        body: formData,
      });
      if (!r.ok) throw new Error(`HTTP ${r.status}`);
      setStatus('success');
    } catch (err) {
      console.error(err);
      setStatus('error');
    }
  }

  return (
    <form onSubmit={handleSubmit}>
      <input name="email" type="email" required />
      <textarea name="message" required />
      <button disabled={status === 'submitting'}>
        {status === 'submitting' ? 'Sending...' : 'Send'}
      </button>
      {status === 'success' && <p>Message sent!</p>}
      {status === 'error'   && <p>Something went wrong. Try again.</p>}
    </form>
  );
}

function DeleteButton({ postId, onDeleted }) {
  const [loading, setLoading] = useState(false);

  // ✅ Event handlers can be async — no useEffect wrapping needed:
  async function handleDelete() {
    if (!confirm('Delete this post?')) return;
    setLoading(true);
    try {
      const r = await fetch(`/api/posts/${postId}`, { method: 'DELETE' });
      if (!r.ok) throw new Error(`HTTP ${r.status}`);
      onDeleted(postId); // notify parent
    } catch (err) {
      alert(`Failed to delete: ${err.message}`);
    } finally {
      setLoading(false);
    }
  }

  return (
    <button onClick={handleDelete} disabled={loading}>
      {loading ? 'Deleting...' : 'Delete'}
    </button>
  );
}

