async function loadUser() {
  const r    = await fetch('/api/user'); // ✅
  const data = await r.json();           // ✅
}

// ❌ No try/catch — if loadUser() rejects, the error is silently swallowed:
async function init() {
  const user = await loadUser();
  render(user);
}
init(); // Promise rejection goes unhandled

// ✅ Always handle rejections:
async function init() {
  try {
    const user = await loadUser();
    render(user);
  } catch (err) {
    showError(err.message);
  }
}

// OR attach .catch() at the call site:
init().catch(err => showError(err.message));

// ❌ SyntaxError — await is only valid inside an async function
function getUser() {
  const user = await fetchUser(1); // SyntaxError
  return user;
}

// ✅ Mark the function async:
async function getUser() {
  const user = await fetchUser(1);
  return user;
}

// ❌ fetch() fulfills even for 404/500 — must check .ok manually:
async function getUser(id) {
  const r    = await fetch(`/api/users/${id}`);
  const user = await r.json(); // may be an error body if status was 404
  return user;
}

// ✅ Always check response.ok:
async function getUser(id) {
  const r = await fetch(`/api/users/${id}`);
  if (!r.ok) throw new Error(`HTTP ${r.status}`);
  return r.json();
}

import { describe, it, expect, vi } from 'vitest';

async function getUsername(id) {
  const r = await fetch(`/api/users/${id}`);
  if (!r.ok) throw new Error(`HTTP ${r.status}`);
  const user = await r.json();
  return user.name;
}

describe('getUsername', () => {
  it('returns user name on success', async () => {
    vi.stubGlobal('fetch', vi.fn().mockResolvedValue({
      ok: true,
      json: () => Promise.resolve({ name: 'Alice' }),
    }));
    // Test async functions with async test callbacks:
    const name = await getUsername(1);
    expect(name).toBe('Alice');
  });

  it('throws on HTTP error', async () => {
    vi.stubGlobal('fetch', vi.fn().mockResolvedValue({
      ok: false,
      status: 404,
    }));
    await expect(getUsername(99)).rejects.toThrow('HTTP 404');
  });
});
